  # annotaties
  LAYER
    NAME "annotaties"
    LABELITEM "label"
    TYPE POINT
    EXTENT -1000000 -1000000 1150000 1900000

    METADATA
      "ows_title" "annotaties"
    END

    SCALETOKEN
      NAME "%scale%"
      VALUES
        "0"        "0"
        "750"      "750"
        "1500"     "1500"
        "3000"     "3000"
        "6000"     "6000"
        "12000"    "12000"
        "24000"    "24000"
        "48000"    "48000"
        "96000"    "96000"
        "192000"   "192000"
        "384000"   "384000"
        "768000"   "768000"
        "1536000"  "1536000"
        "3072000"  "3072000"
        "6144000"  "6144000"
      END # VALUES
    END # SCALETOKEN

    CONNECTIONTYPE OGR
    CONNECTION "/srv/data/gpkg/brtachtergrondkaart.gpkg"
    DATA "annotaties"
    PROCESSING 'NATIVE_FILTER=minscaledenom <= %scale% AND maxscaledenom > %scale%'
    PROCESSING "CLOSE_CONNECTION=DEFER"
    PROCESSING "LABEL_NO_CLIP=ON"
    TEMPLATE "dummy"

    MINSCALEDENOM 0
    MAXSCALEDENOM 6144000

    CLASSITEM viscode
    CLASS
      # plaatsnamen
      NAME "18000"
      EXPRESSION "18000"
      LABEL
        COLOR "#000000"
        FONT "liberation-sans"
        TYPE truetype
        SIZE [size]
        PRIORITY [priority]
        ANTIALIAS TRUE
        PARTIALS TRUE
        BUFFER 5
      END
    END
    CLASS
      # wijknamen
      NAME "18001"
      EXPRESSION "18001"
      LABEL
        COLOR "#000000"
        FONT "liberation-sans-italic"
        TYPE truetype
        SIZE 9
        ANTIALIAS TRUE
        PARTIALS TRUE
        BUFFER 5
        MAXSCALEDENOM 48000
      END
    END
    CLASS
      # A-wegnummers
      NAME "10000"
      EXPRESSION "10000"
      LABEL
        COLOR "#FFFFFF"
        FONT "liberation-sans-bold"
        TYPE truetype
        SIZE 8.8
        OFFSET 0 0
        STYLE
          GEOMTRANSFORM labelpoly
          COLOR "#FF7F7F"
          ANTIALIAS TRUE
        END
        STYLE
          GEOMTRANSFORM "labelpoly"
          OUTLINECOLOR "#FF7F7F"
          WIDTH 4
          LINEJOIN MITER
          LINECAP SQUARE
          ANTIALIAS TRUE
        END
        FORCE TRUE
        PARTIALS TRUE
        ANTIALIAS TRUE
        PRIORITY 9
      END
    END
    CLASS
